import React, { useState } from 'react';
import {
  CButton,
  CModal,
  CModalBody,
  CModalFooter,
  CModalHeader,
  CModalTitle,
} from '@coreui/react';
import PropTypes from 'prop-types';
import { cilTrash } from '@coreui/icons';
import CIcon from '@coreui/icons-react';
import { commonSettings } from 'src/services/common.settings';
import i18n from 'src/i18n';

const DeleteRow = ({ entityName, id, refresh,name ,data}) => {
  const [visible, setVisible] = useState(false);

  const handleDelete = async () => {
    const result = await commonSettings.deleteTableRow( id, data );

    if (result) {
      setVisible(false);
      refresh();
    }
  };

  return (
    <>
      <CButton color="danger" onClick={() => setVisible(true)}>
        <CIcon icon={cilTrash} />
      </CButton>

      <CModal visible={visible} onClose={() => setVisible(false)}>
        <CModalHeader>
          <CModalTitle>
            {i18n.t('deleteElementTitle')} : {i18n.t(entityName)}: {name}
          </CModalTitle>
        </CModalHeader>
        <CModalBody>
          <p>{i18n.t('deleteElementConfirmation')}</p>
        </CModalBody>
        <CModalFooter>
          <CButton color="secondary" onClick={() => setVisible(false)}>
            {i18n.t('closeButton')}
          </CButton>
          <CButton color="danger" onClick={handleDelete}>
            {i18n.t('deleteButton')}
          </CButton>
        </CModalFooter>
      </CModal>
    </>
  );
};

DeleteRow.propTypes = {
  refresh: PropTypes.func.isRequired,
  entityName: PropTypes.string.isRequired,
  name: PropTypes.string.isRequired,
  data: PropTypes.string.isRequired,
  id: PropTypes.oneOfType([PropTypes.string, PropTypes.number]).isRequired,
};

export default DeleteRow;
